import 'bootstrap/dist/css/bootstrap-grid.min.css';
import {BrowserRouter, Routes, Route} from 'react-router-dom';
import MaterialList from './pages/MaterialList';

function App() {
  return (
    <div className="App">
      <BrowserRouter>
        <Routes>
          <Route path='/MaterialList' element={<MaterialList />}> </Route>
        </Routes>
      </BrowserRouter>
    </div>
  );
}

export default App;
